        /// <summary>
        ///   Looks up a localized string similar to SELECT * FROM S_RFQ_Actions WHERE seen = 0 and (ToBU IN (SELECT BusUnitID FROM Alpha_BusinessUnitDef WHERE (BusUnitID IN (SELECT BusUnitID FROM Alpha_BusinessUnitUsers WHERE (UserID = &apos;{1}&apos;) AND (CompNo = &apos;{0}&apos;) AND (Permission = 1))) AND (CompNo = &apos;{0}&apos;))) AND (CompNo = &apos;{0}&apos;)  and sr in(SELECT max(Sr)  FROM S_RFQ_Actions GROUP BY RFQNo).
        /// </summary>
